class PubSub {
  constructor() {
    this.events = {};
  }

  // Subscribe to an event
  on(event, listener) {
    if (!this.events[event]) {
      this.events[event] = [];
    }
    this.events[event].push({ listener, once: false });
  }

  // Subscribe to an event to be triggered only once
  once(event, listener) {
    if (!this.events[event]) {
      this.events[event] = [];
    }
    this.events[event].push({ listener, once: true });
  }

  // Unsubscribe from an event
  off(event, listener) {
    if (!this.events[event]) return;

    this.events[event] = this.events[event].filter(
      subscriber => subscriber.listener !== listener
    );
  }

  // Emit an event, triggering all subscribed listeners
  emit(event, ...args) {
    if (!this.events[event]) return;

    this.events[event] = this.events[event].filter(subscriber => {
      subscriber.listener(...args);
      return !subscriber.once;
    });

    // Handle wildcard events
    for (let key in this.events) {
      if (this.matchesWildcard(event, key)) {
        this.events[key].forEach(subscriber => {
          subscriber.listener(...args);
          if (subscriber.once) {
            this.off(key, subscriber.listener);
          }
        });
      }
    }
  }

  // Check if event matches a wildcard pattern
  matchesWildcard(event, pattern) {
    if (pattern === '*') return true;

    const patternParts = pattern.split('.');
    const eventParts = event.split('.');

    if (patternParts.length !== eventParts.length) return false;

    for (let i = 0; i < patternParts.length; i++) {
      if (patternParts[i] !== '*' && patternParts[i] !== eventParts[i]) {
        return false;
      }
    }

    return true;
  }
}

