class PubSub {
  constructor() {
    this.events = {};
  }

  // Subscribe to an event
  on(event, listener) {
    if (!this.events[event]) {
      this.events[event] = [];
    }
    this.events[event].push({ listener, once: false });
  }

  // Subscribe to an event to be triggered only once
  once(event, listener) {
    if (!this.events[event]) {
      this.events[event] = [];
    }
    this.events[event].push({ listener, once: true });
  }

  // Unsubscribe from an event
  off(event, listener) {
    if (this.events[event]) {
      this.events[event] = this.events[event].filter(
        subscriber => subscriber.listener !== listener
      );
    }
  }

  // Publish an event with data
  emit(event, data) {
    const listeners = [];

    // Add exact match listeners
    if (this.events[event]) {
      listeners.push(...this.events[event]);
    }

    // Add wildcard match listeners
    for (const evt in this.events) {
      if (this._isWildcardMatch(event, evt)) {
        listeners.push(...this.events[evt]);
      }
    }

    // Call listeners and remove 'once' listeners
    listeners.forEach(subscriber => {
      subscriber.listener(data);
      if (subscriber.once) {
        this.off(event, subscriber.listener);
      }
    });
  }

  // Check if event matches wildcard pattern
  _isWildcardMatch(event, pattern) {
    if (pattern === '*') return true; // Match all events
    const regex = new RegExp('^' + pattern.replace(/\*/g, '.*') + '$');
    return regex.test(event);
  }
}

