class EventEmitter {
    constructor() {
        this.events = {};
    }

    // Subscribe to an event with a callback
    on(event, listener) {
        if (!this.events[event]) {
            this.events[event] = [];
        }
        this.events[event].push({ listener, once: false });
    }

    // Subscribe to an event with a callback that will be called only once
    once(event, listener) {
        if (!this.events[event]) {
            this.events[event] = [];
        }
        this.events[event].push({ listener, once: true });
    }

    // Publish an event with optional data
    emit(event, ...args) {
        const eventListeners = this.events[event] || [];
        const wildcardListeners = this.events['*'] || [];

        // Call all specific event listeners
        eventListeners.forEach(({ listener, once }, index) => {
            listener(...args);
            if (once) {
                eventListeners.splice(index, 1);
            }
        });

        // Call all wildcard listeners
        wildcardListeners.forEach(({ listener, once }) => {
            listener(event, ...args);
            if (once) {
                this.events['*'] = this.events['*'].filter(l => l.listener !== listener);
            }
        });
    }

    // Unsubscribe from an event
    off(event, listener) {
        if (!this.events[event]) return;

        this.events[event] = this.events[event].filter(l => l.listener !== listener);
    }

    // Unsubscribe from all events
    clear() {
        this.events = {};
    }
}

