  // e.g. "foo.*.bar" becomes /^foo\.[^.]+\.bar$/
  _patternToRegex(pattern) {
    // Escape any regex special chars except '*'
    const escaped = pattern.replace(/([.?+^$[\]\\(){}|-])/g, "\\$1");
    // Replace '*' with a capturing group (matches one or more characters except '.')
    // But we assume that '*' should match any character sequence including dots.
    // Alternatively, if we want to match segment only, we would use [^.]+?
    // For now we use '.*' to match any char.
    const regexStr = '^' + escaped.replace(/\*/g, '.*') + '$';
    return new RegExp(regexStr);
  }

  // Subscribes to events. Returns an unsubscribe function.
  subscribe(pattern, callback) {
    if (typeof pattern !== 'string') {
      throw new Error('Event pattern must be a string.');
    }
    if (typeof callback !== 'function') {
      throw new Error('Callback must be a function.');
    }
    const regex = this._patternToRegex(pattern);
    const subscription = { pattern, regex, callback, once: false };
    this.subscriptions.push(subscription);
    // Return an unsubscribe function for convenience.
    return () => {
      this.unsubscribe(callback);
    };
  }

  // Once-only subscription.
  subscribeOnce(pattern, callback) {
    if (typeof pattern !== 'string') {
      throw new Error('Event pattern must be a string.');
    }
    if (typeof callback !== 'function') {
      throw new Error('Callback must be a function.');
    }
    const regex = this._patternToRegex(pattern);
    const subscription = { pattern, regex, callback, once: true };
    this.subscriptions.push(subscription);
    return () => {
      this.unsubscribe(callback);
    };
  }

  // Unsubscribe a specific callback. Can also pass the pattern to help remove only matching subscriptions.
  unsubscribe(callback, pattern = null) {
    this.subscriptions = this.subscriptions.filter(sub => {
      const matchCallback = sub.callback !== callback;
      const matchPattern = pattern ? sub.pattern !== pattern : true;
      return matchCallback || !matchPattern;
    });
  }

  // Publish an event with given name and args.
  publish(eventName, ...args) {
    if (typeof eventName !== 'string') {
      throw new Error('Event name must be a string.');
    }
    // Clone subscriptions array to avoid modification issues during publication.
    const subs = this.subscriptions.slice();

    for (const sub of subs) {
      if (sub.regex.test(eventName)) {
        try {
          sub.callback(...args);
        } catch (err) {
          // Log error without stopping other subscriptions
          console.error(`Error in callback for event "${eventName}":`, err);
        }

        // If it's once-only, remove it
        if (sub.once) {
          this.unsubscribe(sub.callback, sub.pattern);
        }
      }
