    const once = !!options.once;
    // If event contains a wildcard, subscribe in wildcardSubscriptions.
    if (event.includes('*')) {
      const regex = this._patternToRegex(event);
      this.wildcardSubscriptions.push({ pattern: event, regex, listener, once });
    } else {
      // Otherwise, use exactSubscriptions as a Map.
      if (!this.exactSubscriptions.has(event)) {
        this.exactSubscriptions.set(event, []);
      }
      this.exactSubscriptions.get(event).push({ listener, once });
    }
    return this; // chaining
  }

