class EventEmitter {
  constructor() {
    this.listeners = new Map();
    this.onceListeners = new Map();
  }

  /**
   * Subscribe to an event with optional wildcard support
   * @param {string} event - Event name (supports wildcards with *)
   * @param {Function} callback - Callback function
   * @returns {Function} Unsubscribe function
   */
  on(event, callback) {
    if (typeof callback !== 'function') {
      throw new Error('Callback must be a function');
    }

    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }

    this.listeners.get(event).add(callback);

    // Return unsubscribe function
    return () => this.off(event, callback);
  }

  /**
   * Subscribe to an event that will only fire once
   * @param {string} event - Event name (supports wildcards with *)
   * @param {Function} callback - Callback function
   * @returns {Function} Unsubscribe function
   */
  once(event, callback) {
    if (typeof callback !== 'function') {
      throw new Error('Callback must be a function');
    }

    if (!this.onceListeners.has(event)) {
      this.onceListeners.set(event, new Set());
    }

    this.onceListeners.get(event).add(callback);

    // Return unsubscribe function
    return () => this.offOnce(event, callback);
  }

  /**
   * Unsubscribe from an event
   * @param {string} event - Event name
   * @param {Function} callback - Callback function to remove
   */
  off(event, callback) {
    const eventListeners = this.listeners.get(event);
    if (eventListeners) {
      eventListeners.delete(callback);
      if (eventListeners.size === 0) {
        this.listeners.delete(event);
      }
    }
  }

  /**
   * Remove a once listener
   * @param {string} event - Event name
   * @param {Function} callback - Callback function to remove
   */
  offOnce(event, callback) {
    const eventListeners = this.onceListeners.get(event);
    if (eventListeners) {
      eventListeners.delete(callback);
      if (eventListeners.size === 0) {
        this.onceListeners.delete(event);
      }
    }
  }

  /**
   * Remove all listeners for an event or all events
   * @param {string} [event] - Event name (optional)
   */
  removeAllListeners(event) {
    if (event) {
      this.listeners.delete(event);
      this.onceListeners.delete(event);
    } else {
      this.listeners.clear();
      this.onceListeners.clear();
    }
  }

  /**
   * Emit an event to all matching listeners
   * @param {string} event - Event name
   * @param {...any} args - Arguments to pass to listeners
   */
  emit(event, ...args) {
    const matchingEvents = this._getMatchingEvents(event);
    let hasListeners = false;

    // Execute regular listeners
    for (const eventPattern of matchingEvents) {
      const eventListeners = this.listeners.get(eventPattern);
      if (eventListeners && eventListeners.size > 0) {
        hasListeners = true;
        for (const callback of eventListeners) {
          try {
            callback(...args);
          } catch (error) {
            console.error(`Error in event listener for "${eventPattern}":`, error);
          }
        }
      }
    }

    // Execute and remove once listeners
    for (const eventPattern of matchingEvents) {
      const onceEventListeners = this.onceListeners.get(eventPattern);
      if (onceEventListeners && onceEventListeners.size > 0) {
        hasListeners = true;
        const listenersToCall = [...onceEventListeners];
        this.onceListeners.delete(eventPattern);

        for (const callback of listenersToCall) {
          try {
            callback(...args);
          } catch (error) {
            console.error(`Error in once event listener for "${eventPattern}":`, error);
          }
        }
      }
    }

    return hasListeners;
  }

  /**
   * Get all event patterns that match the given event
   * @param {string} event - Event name to match against
   * @returns {string[]} Array of matching event patterns
   */
  _getMatchingEvents(event) {
    const matchingEvents = [];
    const allEventPatterns = new Set([
      ...this.listeners.keys(),
      ...this.onceListeners.keys()
    ]);

    for (const pattern of allEventPatterns) {
      if (this._isEventMatch(event, pattern)) {
        matchingEvents.push(pattern);
      }
    }

