   * @param {string} event - Actual event name
   * @param {string} pattern - Pattern to match against (may contain wildcards)
   * @returns {boolean} Whether the event matches the pattern
   */
  _isEventMatch(event, pattern) {
    if (pattern === event) {
      return true;
    }

    if (!pattern.includes('*')) {
      return false;
    }

    // Convert pattern to regex
    const regexPattern = pattern
      .split('*')
      .map(part => part.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
      .join('.*');

    const regex = new RegExp(`^${regexPattern}$`);
    return regex.test(event);
  }

