class EventEmitter {
  constructor() {
    this.listeners = new Map();
    this.onceListeners = new Map();
  }

  /**
   * Subscribe to an event
   * @param {string} event - Event name (supports wildcards with *)
   * @param {Function} callback - Callback function
   * @returns {Function} Unsubscribe function
   */
  on(event, callback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }

    this.listeners.get(event).add(callback);

    return () => this.off(event, callback);
  }

  /**
   * Subscribe to an event that will only fire once
   * @param {string} event - Event name (supports wildcards with *)
   * @param {Function} callback - Callback function
   * @returns {Function} Unsubscribe function
   */
  once(event, callback) {
    if (!this.onceListeners.has(event)) {
      this.onceListeners.set(event, new Set());
    }

    this.onceListeners.get(event).add(callback);

    return () => this.offOnce(event, callback);
  }

  /**
   * Unsubscribe from an event
   * @param {string} event - Event name
   * @param {Function} callback - Callback function to remove
   */
  off(event, callback) {
    if (this.listeners.has(event)) {
      this.listeners.get(event).delete(callback);
      if (this.listeners.get(event).size === 0) {
        this.listeners.delete(event);
      }
    }
  }

  /**
   * Unsubscribe from a once-only event
   * @param {string} event - Event name
   * @param {Function} callback - Callback function to remove
   */
  offOnce(event, callback) {
    if (this.onceListeners.has(event)) {
      this.onceListeners.get(event).delete(callback);
      if (this.onceListeners.get(event).size === 0) {
        this.onceListeners.delete(event);
      }
    }
  }

  /**
   * Emit an event
   * @param {string} event - Event name
   * @param {...any} args - Arguments to pass to callbacks
   */
  emit(event, ...args) {
    // Handle regular listeners
    this._emitToListeners(this.listeners, event, args, false);

    // Handle once listeners
    this._emitToListeners(this.onceListeners, event, args, true);
  }

  /**
   * Internal method to emit to listeners
   * @param {Map} listenersMap - Map of listeners
   * @param {string} event - Event name
   * @param {Array} args - Arguments
   * @param {boolean} isOnce - Whether these are once-only listeners
   */
  _emitToListeners(listenersMap, event, args, isOnce) {
    const matchingEvents = this._getMatchingEvents(listenersMap, event);
    const callbacksToRemove = [];

    for (const [eventPattern, callbacks] of matchingEvents) {
      for (const callback of callbacks) {
        try {
          callback(...args);
          if (isOnce) {
            callbacksToRemove.push([eventPattern, callback]);
          }
        } catch (error) {
          console.error(`Error in event listener for "${eventPattern}":`, error);
        }
      }
    }

    // Remove once listeners after execution
    if (isOnce) {
      for (const [eventPattern, callback] of callbacksToRemove) {
        this.offOnce(eventPattern, callback);
      }
    }
  }

  /**
   * Get all event patterns that match the emitted event
   * @param {Map} listenersMap - Map of listeners
   * @param {string} event - Event name
   * @returns {Array} Array of [eventPattern, callbacks] pairs
   */
  _getMatchingEvents(listenersMap, event) {
    const matching = [];

    for (const [eventPattern, callbacks] of listenersMap) {
      if (this._isEventMatch(eventPattern, event)) {
        matching.push([eventPattern, callbacks]);
      }
    }

    return matching;
  }

  /**
   * Check if an event pattern matches an event name
   * @param {string} pattern - Event pattern (may contain wildcards)
   * @param {string} event - Event name
   * @returns {boolean} Whether the pattern matches
   */
  _isEventMatch(pattern, event) {
    if (pattern === event) {
      return true;
    }

    if (!pattern.includes('*')) {
      return false;
    }

    // Convert wildcard pattern to regex
    const regexPattern = pattern
      .split('*')
      .map(part => part.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
      .join('.*');

    const regex = new RegExp(`^${regexPattern}$`);
    return regex.test(event);
  }

  /**
   * Remove all listeners for a specific event
   * @param {string} event - Event name
   */
  removeAllListeners(event) {
    if (event) {
      this.listeners.delete(event);
      this.onceListeners.delete(event);
    } else {
      this.listeners.clear();
      this.onceListeners.clear();
    }
  }

  /**
   * Get the number of listeners for an event
   * @param {string} event - Event name
   * @returns {number} Number of listeners
   */
  listenerCount(event) {
    const regularCount = this.listeners.has(event) ? this.listeners.get(event).size : 0;
    const onceCount = this.onceListeners.has(event) ? this.onceListeners.get(event).size : 0;
    return regularCount + onceCount;
  }

  /**
   * Get all event names that have listeners
   * @returns {Array<string>} Array of event names
   */
  eventNames() {
    const names = new Set([
      ...this.listeners.keys(),
      ...this.onceListeners.keys()
    ]);
    return Array.from(names);
  }
}

